function x(n: number): string {
  let s: string = ""
  let k: number = 1
  for (let i: number = 0; i <= n; i++) {
    let r: string = ""
    for (let j: number = 0; j < k; j++) {
      r = r + "."
    }
    if (i >= (n / 2)) {
      k--
    } else {
      k++
    }
    s = s + r + "\n"
  }
  return s
}

